import React, { useState, useEffect } from 'react';
import './App.css';
import Terminal from './Terminal';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);

  useEffect(() => {

  }, []);

  const handleBoxClick = (boxName) => {
    setActiveApp(boxName);
  };

  let text = '';

  if (activeApp === 'box1') {
    text = 'Sample text for Box 1';
  } else if (activeApp === 'box2') {
    text = 'Sample text for Box 2';
  } else if (activeApp === 'box3') {
    text = 'Sample text for Box 3';
  }

  const box1Text = activeApp === 'box1' ? 'Scroll Down!' : 'About Me';
  const box2Text = activeApp === 'box2' ? 'Scroll Down!' : 'Projects';
  const box3Text = activeApp === 'box3' ? 'Scroll Down!' : 'Resume';

  let content = null;

  if (activeApp === 'box3') {
    content = (
      <div className="resume-content">
        <h2>John Doe</h2>
        <img src="sample-image.jpg" alt="Profile" />
        <h3>Summary</h3>
        <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</p>
        <h3>Experience</h3>
        <p>Company A - Position A</p>
        <p>Company B - Position B</p>
        <h3>Education</h3>
        <p>University A - Degree A</p>
        <p>University B - Degree B</p>
        <h3>Contact Information</h3>
        <p>Email: johndoe@example.com</p>
        <p>Phone: 123-456-7890</p>
      </div>
    );
  }

  return (
    <div className="App">
      <header className="App-header">
        <Terminal activeApp={activeApp} />
        <div className="box-container">
          <div
            className={`box ${activeApp === 'box1' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box1')}
          >
            <div className="box-content">
              <h3>{box1Text}</h3>
              {activeApp !== 'box1' && <p>My Backstory</p>}
            </div>
          </div>
          <div
            className={`box ${activeApp === 'box2' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box2')}
          >
            <div className="box-content">
              <h3>{box2Text}</h3>
              {activeApp !== 'box2' && <p>Past, Current, and Future Projects</p>}
            </div>
          </div>
          <div
            className={`box ${activeApp === 'box3' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box3')}
          >
            <div className="box-content">
              <h3>{box3Text}</h3>
              {activeApp !== 'box3' && <p>My Resume</p>}
            </div>
          </div>
        </div>
        {activeApp && (
          <div className="text-container">
            {content}
          </div>
        )}
      </header>
    </div>
  );
};

export default App;
